def get_all_drug_names():
    """Return flat list of all drug names and aliases."""
    all_names = []
    for drug, info in MEDICAL_DICTIONARY.items():
        all_names.append(drug)
        all_names.extend(info.get("aliases", []))
    return list(set(all_names))

def find_drug_info(name):
    """Find drug info by name or alias."""
    name_lower = name.lower().strip()
    # Direct match
    if name_lower in MEDICAL_DICTIONARY:
        return MEDICAL_DICTIONARY[name_lower]
    # Alias match
    for drug, info in MEDICAL_DICTIONARY.items():
        if name_lower in [a.lower() for a in info.get("aliases", [])]:
            return {**info, "canonical_name": drug}
    return None
